Here is a complete, well-typed Binary Search Tree implementation in TypeScript:

```typescript
// ─── Type Definitions ────────────────────────────────────────────────────────

type Nullable<T> = T | null;

interface BSTNode<T> {
  value: T;
  left: Nullable<BSTNode<T>>;
  right: Nullable<BSTNode<T>>;
}

interface IBinarySearchTree<T> {
  insert(value: T): void;
  delete(value: T): void;
  search(value: T): Nullable<BSTNode<T>>;
  inorder(): T[];
  isEmpty(): boolean;
  getRoot(): Nullable<BSTNode<T>>;
}

// ─── Node Factory ─────────────────────────────────────────────────────────────

function createNode<T>(value: T): BSTNode<T> {
  return { value, left: null, right: null };
}

// ─── Comparator Type ─────────────────────────────────────────────────────────

/**
 * Returns:
 *  -1 (or any negative) if a < b
 *   0                   if a === b
 *   1 (or any positive) if a > b
 */
type Comparator<T> = (a: T, b: T) => number;

const defaultComparator = <T>(a: T, b: T): number => {
  if (a < b) return -1;
  if (a > b) return 1;
  return 0;
};

// ─── BinarySearchTree Class ───────────────────────────────────────────────────

class BinarySearchTree<T> implements IBinarySearchTree<T> {
  private root: Nullable<BSTNode<T>> = null;
  private readonly compare: Comparator<T>;

  constructor(comparator: Comparator<T> = defaultComparator) {
    this.compare = comparator;
  }

  // ── Public API ─────────────────────────────────────────────────────────────

  isEmpty(): boolean {
    return this.root === null;
  }

  getRoot(): Nullable<BSTNode<T>> {
    return this.root;
  }

  /**
   * Inserts a value into the BST.
   * Duplicate values are ignored.
   * Time complexity: O(h) where h is the height of the tree.
   */
  insert(value: T): void {
    this.root = this.insertNode(this.root, value);
  }

  /**
   * Removes a value from the BST if it exists.
   * Time complexity: O(h) where h is the height of the tree.
   */
  delete(value: T): void {
    this.root = this.deleteNode(this.root, value);
  }

  /**
   * Searches for a value and returns its node, or null if not found.
   * Time complexity: O(h) where h is the height of the tree.
   */
  search(value: T): Nullable<BSTNode<T>> {
    return this.searchNode(this.root, value);
  }

  /**
   * Returns all values in sorted (ascending) order via in-order traversal.
   * Time complexity: O(n).
   */
  inorder(): T[] {
    const result: T[] = [];
    this.inorderTraversal(this.root, result);
    return result;
  }

  // ── Private Helpers ────────────────────────────────────────────────────────

  private insertNode(node: Nullable<BSTNode<T>>, value: T): BSTNode<T> {
    // Base case: found an empty slot — create and return a new node
    if (node === null) {
      return createNode(value);
    }

    const cmp = this.compare(value, node.value);

    if (cmp < 0) {
      // Value is smaller — go left
      node.left = this.insertNode(node.left, value);
    } else if (cmp > 0) {
      // Value is larger — go right
      node.right = this.insertNode(node.right, value);
    }
    // cmp === 0: duplicate, do nothing

    return node;
  }

  private deleteNode(node: Nullable<BSTNode<T>>, value: T): Nullable<BSTNode<T>> {
    // Base case: value not found
    if (node === null) return null;

    const cmp = this.compare(value, node.value);

    if (cmp < 0) {
      // Target is in the left subtree
      node.left = this.deleteNode(node.left, value);
    } else if (cmp > 0) {
      // Target is in the right subtree
      node.right = this.deleteNode(node.right, value);
    } else {
      // Found the node to delete — handle 3 cases:

      // Case 1: Leaf node (no children)
      if (node.left === null && node.right === null) {
        return null;
      }

      // Case 2a: Only right child
      if (node.left === null) {
        return node.right;
      }

      // Case 2b: Only left child
      if (node.right === null) {
        return node.left;
      }

      // Case 3: Two children
      // Replace with in-order successor (smallest value in right subtree),
      // then delete the successor from the right subtree.
      const successor = this.findMin(node.right);
      node.value = successor.value;
      node.right = this.deleteNode(node.right, successor.value);
    }

    return node;
  }

  private searchNode(node: Nullable<BSTNode<T>>, value: T): Nullable<BSTNode<T>> {
    if (node === null) return null;

    const cmp = this.compare(value, node.value);

    if (cmp < 0) return this.searchNode(node.left, value);
    if (cmp > 0) return this.searchNode(node.right, value);
    return node; // cmp === 0: found
  }

  private inorderTraversal(node: Nullable<BSTNode<T>>, result: T[]): void {
    if (node === null) return;
    this.inorderTraversal(node.left, result);
    result.push(node.value);
    this.inorderTraversal(node.right, result);
  }

  /**
   * Returns the node with the minimum value in a given subtree.
   * Assumes the subtree is non-null.
   */
  private findMin(node: BSTNode<T>): BSTNode<T> {
    let current = node;
    while (current.left !== null) {
      current = current.left;
    }
    return current;
  }
}

// ─── Usage Examples ───────────────────────────────────────────────────────────

// --- Numbers ---
const numTree = new BinarySearchTree<number>();

numTree.insert(10);
numTree.insert(5);
numTree.insert(15);
numTree.insert(3);
numTree.insert(7);
numTree.insert(12);
numTree.insert(20);

console.log("Inorder:", numTree.inorder());
// → [3, 5, 7, 10, 12, 15, 20]

console.log("Search 7:", numTree.search(7));
// → { value: 7, left: null, right: null }

console.log("Search 99:", numTree.search(99));
// → null

numTree.delete(5);  // Node with two children
console.log("After deleting 5:", numTree.inorder());
// → [3, 7, 10, 12, 15, 20]

numTree.delete(15); // Node with two children
console.log("After deleting 15:", numTree.inorder());
// → [3, 7, 10, 12, 20]

numTree.delete(3);  // Leaf node
console.log("After deleting 3:", numTree.inorder());
// → [7, 10, 12, 20]

// --- Strings (custom comparator) ---
const strTree = new BinarySearchTree<string>((a, b) => a.localeCompare(b));

strTree.insert("banana");
strTree.insert("apple");
strTree.insert("cherry");
strTree.insert("date");

console.log("String tree inorder:", strTree.inorder());
// → ["apple", "banana", "cherry", "date"]
```

---

## Key Design Decisions

| Decision | Rationale |
|---|---|
| **Generic `<T>`** | Works with numbers, strings, or any custom type |
| **Custom `Comparator<T>`** | Makes the tree flexible for non-primitive types (e.g., objects) |
| **Interface `IBinarySearchTree<T>`** | Enforces the public API contract and is easy to extend or mock |
| **`Nullable<T>` alias** | Cleaner than repeating `T \| null` everywhere |
| **In-order successor for delete** | Standard, correct approach for two-child deletion |
| **Duplicate values ignored** | Common BST convention; easily changed to allow duplicates |
| **Recursive implementation** | Clear and readable; for very deep trees, an iterative version avoids stack overflow |

## Complexity Summary

| Operation | Average Case | Worst Case (skewed tree) |
|---|---|---|
| `insert` | O(log n) | O(n) |
| `delete` | O(log n) | O(n) |
| `search` | O(log n) | O(n) |
| `inorder` | O(n) | O(n) |

For guaranteed O(log n) worst-case performance, consider extending this into a self-balancing tree such as an AVL tree or Red-Black tree.
